import io.grpc.stub.StreamObserver;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class FileUploadServiceImpl extends FileUploadServiceGrpc.FileUploadServiceImplBase {

    @Override
    public StreamObserver<Chunk> upload(StreamObserver<FileResponse> responseObserver) {
        return new StreamObserver<Chunk>() {
            private Path tempFile;
            private long bytesWritten = 0;

            @Override
            public void onNext(Chunk chunk) {
                try {
                    if (tempFile == null) {
                        tempFile = Files.createTempFile("upload", "");
                    }
                    Files.write(tempFile, chunk.getData().toByteArray(), 
                               java.nio.file.StandardOpenOption.CREATE,
                               java.nio.file.StandardOpenOption.APPEND);
                    bytesWritten += chunk.getData().size();
                } catch (IOException e) {
                    responseObserver.onError(e);
                }
            }

            @Override
            public void onError(Throwable t) {
                if (tempFile != null) {
                    try {
                        Files.deleteIfExists(tempFile);
                    } catch (IOException e) {
                        t.addSuppressed(e);
                    }
                }
                responseObserver.onError(t);
            }

            @Override
            public void onCompleted() {
                try {
                    // Process the uploaded file
                    FileResponse.Builder builder = FileResponse.newBuilder()
                            .setMessage("File uploaded successfully")
                            .setBytesWritten(bytesWritten)
                            .setFilePath(tempFile.toAbsolutePath().toString());
                    
                    Path finalPath = Paths.get("/final/path/to/save/" + tempFile.getFileName().toString());
                    Files.move(tempFile, finalPath);
                    responseObserver.onNext(builder.build());
                    responseObserver.onCompleted();
                } catch (IOException e) {
                    onError(e);
                }
            }
        };
    }
}